import React, { useState, useEffect } from 'react';
import getQuestions from '../../api/clientQuestion/getQuestions.api';
import questionDetailes from '../../api/clientQuestion/questionDetailes.api';
import deleteQuestion from '../../api/clientQuestion/deleteQuestion.api';
import '../../reusable.css'
import './Users.css'

const Users = () => {
    const [pageLoading, setPageLoading] = useState(false)
    const [allClients, setAllClients] = useState([])
    const [pageNumber, setPageNumber] = useState(1)
    const [totalPage, setTotalPage] = useState(0)
    const [messageDetailesData, setMessageDetailesData] = useState()

    useEffect(() => {
        handleGetMessages()
    }, [])

    const handleGetMessages = () => {
        getQuestions(pageNumber, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }

    // Pagination func
    const next = () => {
        let page = 0;
        if (pageNumber == totalPage) {
            return;
        }

        page = pageNumber + 1
        setPageNumber(page)
        getQuestions(page, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }

    const previous = () => {
        let page = 0;
        if (pageNumber == 1) {
            return;
        }

        page = pageNumber - 1
        setPageNumber(page)
        getQuestions(page, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }
    // Pagination func

    // Delete func
    const handleDeleteQuestion = (id) => {
        deleteQuestion(id, setPageLoading, handleGetMessages)
    }
    // Delete func

    return (
        <div className="client-container">
            {pageLoading ? <div className="plan-page-loader d-flex justify-content-center align-items-center">
                <span className="page-loader"></span>
            </div> : ''}
            {allClients.length == 0 ? '' : <>
                <div className='client-table'>
                    <table>
                        <tr>
                            <th>navnet</th>
                            <th>Mobilnummer</th>
                            <th>e-mail</th>
                            <th>handling</th>
                            <th>Vision</th>
                        </tr>
                        {allClients.map(client => {
                            return (
                                <tr key={client?._id}>
                                    <td>{client?.name}</td>
                                    <td>{client?.phone}</td>
                                    <td>{client?.email}</td>
                                    <td className='table-action-icon'>
                                        <i class="fa fa-eye" onClick={() => openClientPopup(client._id)} aria-hidden="true"></i>
                                        <i class="fa fa-trash" aria-hidden="true" onClick={() => handleDeleteQuestion(client._id)}></i>
                                    </td>
                                    <td className='table-action-read'>{client?.isRead ? '' : <i class="fa fa-info-circle" aria-hidden="true"></i>}</td>
                                </tr>
                            )
                        })}
                    </table>
                </div>
                <div className="client-pagination">
                    <button onClick={previous}>den forrige</button>
                    <button onClick={next}>den næste</button>
                </div>
            </>}

            {/* Start details popup */}
            <div className="client-popup d-none" id="question-popup">
                <div className="client-popup-content">
                    <span className="close-btn" onClick={closeClientPopup} id="close-btn">&times;</span>
                    <h2>Besked detaljer</h2>
                    <h4>navnet:</h4>
                    <p>{messageDetailesData?.name}</p>
                    <h4>e-mail:</h4>
                    <p>{messageDetailesData?.email}</p>
                    <h4>Mobilnummer:</h4>
                    <p>{messageDetailesData?.phone}</p>
                    <h4>Spørgsmål:</h4>
                    <p>{messageDetailesData?.question}</p>
                    <button onClick={closeClientPopup}>lukning</button>
                </div>
            </div>
            {/* End details popup */}
        </div>
    );
}

export default Users;
